public class ConfigurationExport extends AbstractConfigurationCommand { private static final Logger LOG = LoggerFactory . getLogger ( ConfigurationExport . class ) ; private static final String EXPORT_HELP_MESSAGE = "configuration --export {WHERE-DIR}" ; private static final String EXPORT_FILE_NAME = "/content.xml" ; private final Input input ; public ConfigurationExport ( final Input input ) { this . input = input ; } public void export ( ) { if ( input . parameterNumber ( ) == 1 ) { try { XMLUtils . createXMLFile ( ( InputStream ) configurationSyncopeOperations . export ( ) . getEntity ( ) , input . firstParameter ( ) + EXPORT_FILE_NAME ) ; configurationResultManager . genericMessage ( input . firstParameter ( ) + EXPORT_FILE_NAME + " successfully created" ) ; } catch ( final IOException ex ) { LOG . error ( "Error exporting configuration" , ex ) ; configurationResultManager . genericError ( ex . getMessage ( ) ) ; } catch ( ParserConfigurationException | SAXException | TransformerConfigurationException ex ) { LOG . error ( "Error exporting configuration" , ex ) ; configurationResultManager . genericError ( "Error creating " + input . firstParameter ( ) + EXPORT_FILE_NAME + " " + ex . getMessage ( ) ) ; } catch ( final TransformerException ex ) { LOG . error ( "Error exporting configuration" , ex ) ; if ( ex . getCause ( ) instanceof FileNotFoundException ) { configurationResultManager . genericError ( "Permission denied on " + input . firstParameter ( ) ) ; } else { configurationResultManager . genericError ( "Error creating " + input . firstParameter ( ) + EXPORT_FILE_NAME + " " + ex . getMessage ( ) ) ; } } catch ( final SyncopeClientException ex ) { LOG . error ( "Error exporting configuration" , ex ) ; configurationResultManager . genericError ( "Error calling configuration service " + ex . getMessage ( ) ) ; } } else { configurationResultManager . commandOptionError ( EXPORT_HELP_MESSAGE ) ; } } }